def simulate_fa_cup_tie(home_score, away_score, round_type='early'):
    if round_type == 'early':
        if home_score > away_score:
            return "Home team wins"
        elif home_score < away_score:
            return "Away team wins"
        else:
            return "Replay needed"
    else:  # semi-final or final
        if home_score > away_score:
            return "Home team wins"
        elif home_score < away_score:
            return "Away team wins"
        else:
            return "Extra-time and penalties required"

# Example usage:
print(simulate_fa_cup_tie(2, 1))  # Early round: Home team wins
print(simulate_fa_cup_tie(1, 1, 'semi'))  # Semi-final: Extra-time and penalties required
